module RefModule(
    input A,
    input B,
    input C,
    input D,
    output X,
    input VPB,
    input VPWR,
    input VGND,
    input VNB
);wire unused_AB, CD, ABCD;

// OR gate for A and B
or AB_or(unused_AB, A, B);

// OR gate for C and D
or CD_or(CD, C, D);

// OR gate for unused_AB and CD
or ABCD_or(ABCD, unused_AB, CD);

